 29→/**
 30→ * Binding + additional contextual information
 31→ * Also defines equality over bindings.
 32→ * https://stackoverflow.com/questions/5453226/java-need-a-hash-map-where-one-supplies-a-function-to-do-the-hashing
 33→ */
 34→class MappableBinding(val binding: Binding, private val screen: Screen) {
 35→    val isKey: Boolean get() = binding.isKey
 36→
 37→    override fun equals(other: Any?): Boolean {
 38→        if (this === other) {
 39→            return true
 40→        }
 41→        if (other == null || javaClass != other.javaClass) {
 42→            return false
 43→        }
 44→        val otherMappableBinding = other as MappableBinding
 45→
 46→        val otherBinding = otherMappableBinding.binding
 47→        val bindingEquals = binding.keycode == otherBinding.keycode &&
 48→            binding.unicodeCharacter == otherBinding.unicodeCharacter &&
 49→            binding.gesture == otherBinding.gesture &&
 50→            modifierEquals(otherBinding.modifierKeys)
 51→
 52→        if (!bindingEquals) {
 53→            return false
 54→        }
 55→
 56→        return screen.screenEquals(otherMappableBinding.screen)
 57→    }
 58→
 59→    override fun hashCode(): Int {
 60→        // don't include the modifierKeys or mSide
 61→        return Objects.hash(binding.keycode, binding.unicodeCharacter, binding.gesture, screen.prefix)
 62→    }
 63→
 64→    private fun modifierEquals(keys: Binding.ModifierKeys?): Boolean {
 65→        // equals allowing subclasses
 66→        val thisKeys = binding.modifierKeys
 67→        if (thisKeys === keys) {
 68→            return true
 69→        }
 70→        // one is null
 71→        return if (keys == null || thisKeys == null) {
 72→            false
 73→        } else {
 74→            (thisKeys.shiftMatches(true) == keys.shiftMatches(true) || thisKeys.shiftMatches(false) == keys.shiftMatches(false)) &&
 75→                (thisKeys.ctrlMatches(true) == keys.ctrlMatches(true) || thisKeys.ctrlMatches(false) == keys.ctrlMatches(false)) &&
 76→                (thisKeys.altMatches(true) == keys.altMatches(true) || thisKeys.altMatches(false) == keys.altMatches(false))
 77→        }
 78→
 79→        // Perf: Could get a slight improvement if we check that both instances are not subclasses
 80→
 81→        // allow subclasses to work - a subclass which overrides shiftMatches will return true on one of the tests
 82→    }
 83→
 84→    fun toDisplayString(context: Context): String {
 85→        return screen.toDisplayString(context, binding)
 86→    }
 87→
 88→    fun toPreferenceString(): String? {
 89→        return screen.toPreferenceString(binding)
 90→    }
 91→
 92→    abstract class Screen private constructor(val prefix: Char) {
 93→        abstract fun toPreferenceString(binding: Binding): String?
 94→        abstract fun toDisplayString(context: Context, binding: Binding): String
 95→        abstract fun screenEquals(otherScreen: Screen): Boolean
 96→
 97→        class Reviewer(val side: CardSide) : Screen('r') {
 98→            override fun toPreferenceString(binding: Binding): String? {
 99→                if (!binding.isValid) {
100→                    return null
101→                }
102→                val s = StringBuilder()
103→                s.append(prefix)
104→                s.append(binding.toString())
105→                // don't serialise problematic bindings
106→                if (s.isEmpty()) {
107→                    return null
108→                }
109→                when (side) {
110→                    CardSide.QUESTION -> s.append('0')
111→                    CardSide.ANSWER -> s.append('1')
112→                    CardSide.BOTH -> s.append('2')
113→                }
114→                return s.toString()
115→            }
116→
117→            override fun toDisplayString(context: Context, binding: Binding): String {
118→                val formatString = when (side) {
119→                    CardSide.QUESTION -> context.getString(R.string.display_binding_card_side_question)
120→                    CardSide.ANSWER -> context.getString(R.string.display_binding_card_side_answer)
121→                    else -> context.getString(R.string.display_binding_card_side_both) // intentionally no prefix
122→                }
123→                return String.format(formatString, binding.toDisplayString(context))
124→            }
125→
126→            override fun screenEquals(otherScreen: Screen): Boolean {
127→                val other: Reviewer = otherScreen as? Reviewer ?: return false
128→
129→                return side === CardSide.BOTH ||
130→                    other.side === CardSide.BOTH ||
131→                    side === other.side
132→            }
133→
134→            companion object {
135→                @CheckResult
136→                fun fromGesture(b: Binding): MappableBinding = MappableBinding(b, Reviewer(CardSide.BOTH))
137→                fun fromString(s: String): MappableBinding {
138→                    val binding = s.substring(0, s.length - 1)
139→                    val b = Binding.fromString(binding)
140→                    val side = when (s[s.length - 1]) {
141→                        '0' -> CardSide.QUESTION
142→                        '1' -> CardSide.ANSWER
143→                        else -> CardSide.BOTH
144→                    }
145→                    return MappableBinding(b, Reviewer(side))
146→                }
147→            }
148→        }
149→    }
150→
151→    /** the serialisation version */
152→    enum class Version {
153→        ONE
154→    }
155→
156→    companion object {
157→        const val PREF_SEPARATOR = '|'
158→
159→        @CheckResult
160→        fun fromGesture(gesture: Gesture): MappableBinding = MappableBinding(Binding(gesture), Screen.Reviewer(CardSide.BOTH))
161→
162→        @CheckResult
163→        fun List<MappableBinding>.toPreferenceString(): String = this.mapNotNull { it.toPreferenceString() }
164→            .joinToString(prefix = "1/", separator = PREF_SEPARATOR.toString())
165→
166→        @Suppress("UNUSED_PARAMETER")
167→        @CheckResult
168→        fun fromString(s: String, v: Version = Version.ONE): MappableBinding? {
169→            if (s.isEmpty()) {
170→                return null
171→            }
172→            return try {
173→                // the prefix of the serialized
174→                when (s[0]) {
175→                    'r' -> Screen.Reviewer.fromString(s.substring(1))
176→                    else -> null
177→                }
178→            } catch (e: Exception) {
179→                Timber.w(e, "failed to deserialize binding")
180→                null
181→            }
182→        }
183→
184→        @CheckResult
185→        fun fromPreferenceString(string: String?): MutableList<MappableBinding> {
186→            if (string.isNullOrEmpty()) return ArrayList()
187→            try {
188→                val version = string.takeWhile { x -> x != '/' }
189→                val remainder = string.substring(version.length + 1) // skip the /
190→                if (version != "1") {
191→                    Timber.w("cannot handle version '$version'")
192→                    return ArrayList()
193→                }
194→                return remainder.split(PREF_SEPARATOR).mapNotNull { fromString(it) }.toMutableList()
195→            } catch (e: Exception) {
196→                Timber.w(e, "Failed to deserialize preference")
197→                return ArrayList()
198→            }
199→        }
200→
201→        @CheckResult
202→        fun fromPreference(prefs: SharedPreferences, command: ViewerCommand): MutableList<MappableBinding> {
203→            val value = prefs.getString(command.preferenceKey, null) ?: return command.defaultValue.toMutableList()
204→            return fromPreferenceString(value)
205→        }
206→
207→        @CheckResult
208→        fun allMappings(prefs: SharedPreferences): MutableList<Pair<ViewerCommand, MutableList<MappableBinding>>> {
209→            return ViewerCommand.values().map {
210→                Pair(it, fromPreference(prefs, it))
211→            }.toMutableList()
212→        }
213→    }
214→}
