package com.ichi2.anki.preferences

import android.util.Xml
import androidx.test.ext.junit.runners.AndroidJUnit4
import com.ichi2.anki.R
import com.ichi2.anki.RobolectricTest
import com.ichi2.anki.cardviewer.ViewerCommand
import org.hamcrest.MatcherAssert.assertThat
import org.hamcrest.Matchers.`is`
import org.hamcrest.Matchers.empty
import org.junit.Test
import org.junit.runner.RunWith
import org.xmlpull.v1.XmlPullParser

@RunWith(AndroidJUnit4::class)
class ControlsCommandsXmlTest : RobolectricTest() {

    @Test
    fun allViewerCommandsArePresentInPreferencesControlsXml() {
        val androidNs = "http://schemas.android.com/apk/res/android"

        val parser: XmlPullParser = targetContext.resources.getXml(R.xml.preferences_controls)
        val commandPreferenceKeys = mutableSetOf<String>()

        while (parser.eventType != XmlPullParser.END_DOCUMENT) {
            if (parser.eventType == XmlPullParser.START_TAG && parser.name == "com.ichi2.preferences.ControlPreference") {
                val key = parser.getAttributeValue(androidNs, "key")
                if (key != null) {
                    commandPreferenceKeys.add(key)
                }
            }
            parser.next()
        }

        val expectedKeys = ViewerCommand.values().map { it.preferenceKey }.toSet()
        val missing = expectedKeys - commandPreferenceKeys

        assertThat("Missing command preferences in preferences_controls.xml: $missing", missing, `is`(empty()))
    }
}
